<section class="container section"><h1>Hoteles</h1><form class="filters"><input type="hidden" name="route" value="hotels"><select name="destination"><option value="0">Todos los destinos</option><?php foreach($destinations as $d):?><option value="<?=$d['id']?>" <?=$selected==$d['id']?'selected':''?>><?=Security::e($d['name'])?></option><?php endforeach;?></select><button class="btn small">Filtrar</button></form><div class="grid"><?php foreach($hotels as $h):?><article class="card"><img src="<?=Security::e($h['image'])?>"><div class="card-body"><small><?=Security::e($h['destination_name'])?> · <?=$h['category']?> estrellas</small><h3><?=Security::e($h['name'])?></h3><p><?=Security::e($h['description'])?></p><strong>₡<?=number_format($h['price_per_night'])?> / noche</strong></div></article><?php endforeach;?></div></section>
